import{_ as o}from"./chunks/afdian.BUdhV4x0.js";import{p as r,bh as s,I as i,U as a,A as e}from"./chunks/framework.BpabEsSf.js";const b=JSON.parse('{"title":"Project Introduction","description":"","frontmatter":{"title":"Project Introduction","date":"2026-05-01T23:30:00.000Z","permalink":"/guide/intro","categories":["Introduction"],"tags":["Project"]},"headers":[],"relativePath":"en/01.Guide/01.Introduction/01.Project Introduction.md","filePath":"en/01.Guide/01.Introduction/01.Project Introduction.md","lastUpdated":1778928321000}'),n={name:"en/01.Guide/01.Introduction/01.Project Introduction.md"};function c(d,t,l,p,h,u){return s(),i("div",null,[...t[0]||(t[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /en\\01.Guide\\01.Introduction\\01.Project Introduction.md for this page in Markdown format</div><h1 id="project-introduction" tabindex="-1">Project Introduction <a class="header-anchor" href="#project-introduction" aria-label="Permalink to &quot;Project Introduction&quot;">​</a></h1><h1 align="center">Monica Local Vault</h1><p align="center"><strong>A Local-First Password Vault Aggregating Bitwarden &amp; KeePass</strong></p><p align="center">Android / Browser · Local Vault · TOTP · WebDAV Backup</p>',5),e("div",{class:"container share-card-container"},[e("div",{class:"share-card index-auto",style:{"--row-gap":"20px","--column-gap":"20px","--column-min-width":"calc(100% / 4 - 60px)"}},[e("a",{href:"https://github.com/JoyinJoester",target:"_blank",class:"share-card__item row-4",style:{"--item-bg-color":"#FFB6C1","--item-text-color":"#621529"}},[e("div",{class:"share-card__item__img skeleton-image"},[e("img",{src:"https://avatars.githubusercontent.com/u/87232423",alt:"JoyinJoester",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),e("div",{class:"share-card__item__content"},[e("p",{class:"name"},"JoyinJoester"),e("p",{class:"desc"},"Let me tell you the legendary story of this passionate developer.")])]),e("a",{href:"https://afdian.com/a/JoyinJoester",target:"_blank",class:"share-card__item row-4",style:{"--item-bg-color":"#FFEBF2","--item-text-color":"#621529"}},[e("div",{class:"share-card__item__img skeleton-image"},[e("img",{src:o,alt:"Sponsorship & Support",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),e("div",{class:"share-card__item__content"},[e("p",{class:"name"},"Sponsorship & Support"),e("p",{class:"desc"},"Support an independent developer's full-time passion with a cup of coffee!")])])])],-1),e("div",{class:"container nav-card-container"},[e("div",{class:"nav-card index-auto",style:{"--row-gap":"20px","--column-gap":"20px","--column-min-width":"calc(100% / 4 - 60px)"}},[e("a",{href:"http://www.linux.do/",target:"_blank",class:"nav-card__item row-4",style:{"--desc-line-clamp":"2"}},[e("div",{class:"nav-card__item__info"},[e("div",{class:"nav-card__item__img skeleton-image"},[e("img",{src:"https://linux.do/logo-128.svg",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),e("span",{class:"name"},"Linux Do")]),e("p",{class:"desc"},"L-Station, a community for sharing tutorials and tech news."),e("span",{class:"VPBadge tip badge"},"Friendly Link")]),e("a",{href:"https://qm.qq.com/q/2vTdTkHV3u",target:"_blank",class:"nav-card__item row-4",style:{"--desc-line-clamp":"2"}},[e("div",{class:"nav-card__item__info"},[e("div",{class:"nav-card__item__img skeleton-image"},[e("img",{src:"https://p.qlogo.cn/gh/1087865010/1087865010/",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),e("span",{class:"name"},"QQ Group")]),e("p",{class:"desc"},"Join the QQ community group (1087865010) to chat, give feedback, and interact with the developer."),e("span",{class:"VPBadge info badge"},"Chat Group")])])],-1),a('<div class="danger custom-block"><p class="custom-block-title">⚠️ Secure Backup Reminder</p><p><strong>Your data privacy is priceless! Please ensure you make regular backups across multiple storage media!</strong></p><p>Make sure to back up your vault properly. Data privacy is invaluable! Do not keep all your eggs in one basket—avoid relying entirely on a single software application!</p></div><p><code>Monica</code> is a local password vault (Local Vault) that aggregates <strong>Bitwarden</strong> and <strong>KeePass</strong> ecosystems. Built on a local-first architecture, it helps you uniformly manage accounts, passwords, 2FA tokens, private notes, and sensitive attachments across Android and desktop browsers.</p><div class="info custom-block"><p class="custom-block-title">📌 Project Updates Notice</p><ul><li><strong>Monica for Windows</strong> has been archived. Check historical code here: <a href="https://github.com/JoyinJoester/Monica-for-Windows" target="_blank" rel="noreferrer"><code>Monica-for-Windows</code></a></li><li>⏳ Due to finite development bandwidth, <code>Monica for Wear</code> and <code>Monica for Browser</code> are temporarily <strong>not actively updated</strong>.</li><li>🎯 At this stage, full focus is dedicated to the feature completeness, user experience optimization, and stability maintenance of <strong><code>Monica for Android</code></strong>. Thank you for your understanding.</li></ul></div><h2 id="🧭-user-guide" tabindex="-1">🧭 User Guide <a class="header-anchor" href="#🧭-user-guide" aria-label="Permalink to &quot;🧭 User Guide&quot;">​</a></h2><h3 id="🎯-who-is-monica-for" tabindex="-1">🎯 Who is Monica For? <a class="header-anchor" href="#🎯-who-is-monica-for" aria-label="Permalink to &quot;🎯 Who is Monica For?&quot;">​</a></h3><ul><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled>Users who prefer <strong>local-first</strong> credential management and do not want their sensitive account data hosted on third-party cloud servers.</li><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled>Dual-ecosystem players who use <strong>Bitwarden</strong> features but also maintain <strong>KeePass</strong> (<code>.kdbx</code>) databases.</li><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled>Anyone looking for an efficient Android client combined with <strong>intelligent autofill</strong> capabilities on browsers.</li></ul><h3 id="🎁-what-you-get" tabindex="-1">🎁 What You Get <a class="header-anchor" href="#🎁-what-you-get" aria-label="Permalink to &quot;🎁 What You Get&quot;">​</a></h3><ul><li><strong>Local Encrypted Safe</strong>: Securely store login credentials, payment cards, IDs, secure notes, and attachments.</li><li><strong>Dual-Ecosystem Aggregation</strong>: Integrates Bitwarden API synchronization alongside native KeePass (<code>.kdbx</code>) read/write capabilities on Android.</li><li><strong>Diversified Sync &amp; Backup</strong>: Securely transfer data across devices using your own self-hosted WebDAV infrastructure.</li><li><strong>Built-in TOTP</strong>: Manage both standard passwords and secondary two-factor authentication codes inside a single application.</li></ul><h2 id="📱-android-highlights" tabindex="-1">📱 Android Highlights <a class="header-anchor" href="#📱-android-highlights" aria-label="Permalink to &quot;📱 Android Highlights&quot;">​</a></h2><h3 id="✨-core-features" tabindex="-1">✨ Core Features <a class="header-anchor" href="#✨-core-features" aria-label="Permalink to &quot;✨ Core Features&quot;">​</a></h3><ul><li><strong>Local Vault</strong> — All core credentials are encrypted natively using high-strength storage algorithms.</li><li><strong>Aggregated Import</strong> — Fully supports seamless migration from KeePass files and flexible integration with Bitwarden ecosystems.</li><li><strong>Smart Search</strong> — Quickly locate your targets using multi-dimensional queries across titles, domains, and custom tags.</li><li><strong>Biometric Authentication</strong> — Leverages system-level biometric prompts (Fingerprint/Face Unlock) for instant yet airtight security.</li><li><strong>TOTP Management</strong> — Consolidates, organizes, and dynamically generates 2FA authentication codes.</li></ul><h3 id="🛠️-technical-stack" tabindex="-1">🛠️ Technical Stack <a class="header-anchor" href="#🛠️-technical-stack" aria-label="Permalink to &quot;🛠️ Technical Stack&quot;">​</a></h3><p>The architecture strictly follows Modern Android Development (MAD) practices:</p><table tabindex="0"><thead><tr><th>Architectural Layer</th><th>Technologies &amp; Components</th></tr></thead><tbody><tr><td><strong>UI Presentation Layer</strong></td><td><code>Jetpack Compose</code> + <code>Material 3</code> + <code>Navigation Compose</code></td></tr><tr><td><strong>Data Persistence Layer</strong></td><td><code>Room</code> (<code>PasswordDatabase</code>) + Data Access Objects (DAO) + Repository Pattern</td></tr><tr><td><strong>Asynchronous/Concurrency</strong></td><td>Kotlin <code>Coroutines</code> + <code>Flow</code> responsive data streams</td></tr><tr><td><strong>Dependency Injection (DI)</strong></td><td><code>Koin</code> (highly cohesive setup initialized at app startup within <code>MonicaApplication</code>)</td></tr><tr><td><strong>Background Scheduling</strong></td><td><code>WorkManager</code> (lightweight, reliable automated WebDAV backups driven by <code>AutoBackupWorker</code>)</td></tr><tr><td><strong>Protocols &amp; Integrations</strong></td><td><code>Retrofit</code> + <code>OkHttp</code> (Bitwarden API)<br></td></tr></tbody></table><p><br><code>kotpass</code> (Core KeePass parsing Engine)<br></p><p><br><code>sardine-android</code> (WebDAV client) |</p><h3 id="🔒-pure-security-model" tabindex="-1">🔒 Pure Security Model <a class="header-anchor" href="#🔒-pure-security-model" aria-label="Permalink to &quot;🔒 Pure Security Model&quot;">​</a></h3><p>Security is the core foundation of a password manager. Monica implements rigorous architectural defenses at the lowest level:</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>1. Core Cryptographic Algorithm</strong> Implements the <strong><code>AES-256-GCM</code></strong> authenticated encryption scheme, ensuring complete data confidentiality alongside full-scale integrity checks to prevent tampering.</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>2. Key Derivation Function (KDF)</strong> Employs the <strong><code>PBKDF2-HMAC-SHA256</code></strong> algorithm with highly intensive iteration parameters, drastically raising the technical barrier and time-cost for brute-force attacks.</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>3. Hardware-Backed Local Protection</strong> The master password hash and core security configurations are securely delegated to the system-level <strong><code>Android Keystore</code></strong>, <strong><code>EncryptedSharedPreferences</code></strong>, and <strong><code>BiometricPrompt</code></strong>, keeping encryption keys entirely within hardware-isolated environments.</p></div><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p><strong>4. Explicit Network Boundaries</strong> The application&#39;s declared network permissions are <strong>exclusively</strong> utilized for user-triggered workflows—such as Bitwarden API interactions and WebDAV synchronization. It contains absolutely zero third-party telemetry, trackers, or hidden analytics.</p></div><h2 id="🤝-open-source-acknowledgements" tabindex="-1">🤝 Open Source Acknowledgements <a class="header-anchor" href="#🤝-open-source-acknowledgements" aria-label="Permalink to &quot;🤝 Open Source Acknowledgements&quot;">​</a></h2><p>The design, compatibility design, and features of <code>Monica</code> are deeply inspired by the open-source community. We sincerely appreciate the following projects and software:</p><ul><li><strong><a href="https://github.com/AChep/keyguard-app" target="_blank" rel="noreferrer">Keyguard</a></strong> — Excellent reference for an exceptional, sleek Android password manager user experience.</li><li><strong><a href="https://bitwarden.com/" target="_blank" rel="noreferrer">Bitwarden</a></strong> — Vital reference for open-source password ecosystems, data schemas, and multi-client synchronization.</li><li><strong><a href="https://keepass.info/" target="_blank" rel="noreferrer">KeePass</a></strong> — The pioneer of local password storage, serving as the baseline foundation for our <code>.kdbx</code> file reading and writing.</li><li><strong><a href="https://github.com/stratumauth/app" target="_blank" rel="noreferrer">Stratum Auth</a></strong> — Guidance for 2FA user experiences, beautiful brand icon packages, and verification standards.</li></ul><h2 id="📈-star-history" tabindex="-1">📈 Star History <a class="header-anchor" href="#📈-star-history" aria-label="Permalink to &quot;📈 Star History&quot;">​</a></h2><div class="center tk-center-container"><p>Click the chart below to navigate to the full star history dashboard.</p></div><h2 id="📑-licenses-asset-attributes" tabindex="-1">📑 Licenses &amp; Asset Attributes <a class="header-anchor" href="#📑-licenses-asset-attributes" aria-label="Permalink to &quot;📑 Licenses &amp; Asset Attributes&quot;">​</a></h2><div class="note custom-block"><p class="title note-title custom-block-title">License Declaration</p><p>Copyright (c) 2025 JoyinJoester</p><p>This project is released strictly under the terms of the <strong><a href="https://www.google.com/search?q=LICENSE" target="_blank" rel="noreferrer">GNU General Public License v3.0</a></strong>. You are free to distribute, modify, and build upon this software in compliance with the license provisions.</p></div><h2 id="📦-third-party-icons-trademark-notices" tabindex="-1">📦 Third-Party Icons &amp; Trademark Notices <a class="header-anchor" href="#📦-third-party-icons-trademark-notices" aria-label="Permalink to &quot;📦 Third-Party Icons &amp; Trademark Notices&quot;">​</a></h2><p>To deliver a more streamlined 2FA account management experience, this project packs and references several local static assets:</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ol><li><strong>Icon Asset References</strong>: This project incorporates pre-packaged icon assets (version <code>v1.4.0</code>, containing <code>icons</code> and <code>extraicons</code> folders) courtesy of the <a href="https://github.com/stratumauth/app" target="_blank" rel="noreferrer">Stratum Auth app</a>. These assets are similarly licensed under GPL-3.0. Special thanks to the original creator for their selfless contribution.</li><li><strong>Trademarks</strong>: All third-party brand names, registered trademarks, and commercial logos mentioned in the documentation or app remain the exclusive property of their respective legitimate owners.</li></ol></div>',32)])])}const f=r(n,[["render",c]]);export{b as __pageData,f as default};
